import { describe, it, expect } from "vitest";
import { calculateBasePremium, calculatePremium } from "./quote.js";
import { calculateInsuranceSum, processClaim } from "./claim.js";

describe("Quote - base premium (item prices and building blocks)", () => {
  it.todo("empty item list → base premium 0 G");

  it.todo("single sword → base premium 100 G");
  it.todo("single amulet → base premium 60 G");
  it.todo("single staff → base premium 80 G");
  it.todo("single potion → base premium 40 G");
  it.todo("single rune → base premium 25 G");
  it.todo("single moonstone → base premium 25 G");

  it.todo("2 runes → base premium 50 G (2×25, no block)");
  it.todo("3 runes → base premium 60 G (block of 3 applies at 60 instead of 75)");
  it.todo("4 runes → base premium 100 G (no block: block requires exactly 3)");
  it.todo("7 runes → base premium 175 G (no block)");

  it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks of 60 each)");
});

describe("Quote - full premium calculation", () => {
  it.todo("empty item list → premium 5 G (only the processing fee)");

  it.todo("single sword, new customer (0 years, first contract) → premium 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("single amulet, new customer → premium 71 G (60 base + 6 first-insurance + 5 fee)");
  it.todo("single staff, new customer → premium 93 G (80 base + 8 first-insurance + 5 fee)");
  it.todo("single potion, new customer → premium 49 G (40 base + 4 first-insurance + 5 fee)");
  it.todo("single rune, new customer → premium 33 G (25 base + 2.5 first-insurance + 5 fee = 32.5 → 33 rounded up)");

  it.todo("cursed sword, new customer → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");

  it.todo("sword enchantment 5, new customer → premium 145 G (100 base + 30 enchantment + 10 first-insurance + 5 fee)");
  it.todo("sword enchantment 4, new customer → premium 115 G (no high-enchantment surcharge below 5)");
  it.todo("sword enchantment 5 + cursed, new customer → premium 195 G (100 base + 30 enchantment + 50 curse + 10 first-insurance + 5 fee)");

  it.todo("cursed sword + plain amulet, new customer → premium 231 G (160 base + 50 curse on sword only + 16 first-insurance + 5 fee)");

  it.todo("sword, customer with 2 years, first contract → premium 95 G (100 base + 10 first-insurance − 20 loyalty + 5 fee)");
  it.todo("sword, customer with 1 year, first contract → premium 115 G (no loyalty discount below 2 years)");

  it.todo("sword, new customer, second contract → premium 100 G (100 base + 10 first-insurance − 15 follow-up + 5 fee)");

  it.todo("newcomer with cursed sword (0 years, first contract) → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");

  it.todo("long-standing customer (3 years), second contract, cursed sword enchantment 7 → premium 160 G (100 + 50 curse + 30 enchantment − 20 loyalty + 10 first-insurance − 15 follow-up + 5 fee)");

  it.todo("first insurance surcharge applies per item in every quote regardless of customer history (verified by above test)");

  it.todo("premium rounding: intermediate fractions kept, final 197.5 G rounds up to 198 G in MHPCO's favor");
});

describe("Claim - insurance sum", () => {
  it.todo("sword + amulet → insurance sum 1600 G (1000 + 600), cap 3200 G");
  it.todo("cursed sword → insurance sum 1000 G, cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (1000 + 3×250); block discount affects premium only");
  it.todo("two swords → insurance sum 2000 G (2×1000), cap 4000 G");
});

describe("Claim - payout calculation", () => {
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full reimbursement minus 100 G deductible)");
  it.todo("rune damage 200 G → payout 100 G (full reimbursement minus 100 G deductible; no enchantment or material)");

  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% first: 500, then −100 deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G (both clauses apply, 50% rule wins: 500 − 100 deductible)");
  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (only dragon clause: full reimbursement − 100 deductible)");

  it.todo("dragon attack damages sword 500 G and amulet 300 G → payout 600 G (500−100 + 300−100 = 400 + 200)");

  it.todo("two insured swords damaged → each treated as separate damage with own 100 G deductible");
});

describe("Claim - cap exhaustion", () => {
  it.todo("sword insured (insurance sum 1000, cap 2000), first claim 1500 G → payout 1400 G, remaining cap 600 G");
  it.todo("same policy, second claim 1500 G → payout 600 G, remaining cap 0 G (reduced to remaining cap)");
});

describe("Claim - item type validation", () => {
  it.todo("damages has more entries of a type than insured count → error (non-zero exit), whole claim rejected");
});

describe("Claim - payout rounding", () => {
  it.todo("payout rounding: 350.5 G → 350 G (rounded down in MHPCO's favor)");
});

describe("CLI error handling", () => {
  it.todo("quote includes unknown item type (broomstick) → non-zero exit + error on stderr, no results on stdout");
  it.todo("claim references damage for item not in policy → non-zero exit + error on stderr");
  it.todo("claim contains damage with negative amount → non-zero exit + error on stderr");
});

describe("Multi-step CLI scenarios", () => {
  it.todo("schema example: quote amulet then claim damage 200 → premium 71 G, payout 100 G, remainingCap 1100 G");
});

